#!/usr/bin/env python3
"""
apply_gate_funnel_v286.py  (SentCom v19.34.286, rebuild b — DGX-anchored)

Idempotent applier for the alert->trade GATE near-miss funnel in symbol-trace.
Rebuilt against the live DGX scanner.py (targeted hunks, drift-proof).

WHAT IT DOES
  backend/routers/scanner.py :: /symbol-trace
    - adds _drop_margin() + _summarize_symbol_drops() helpers
    - joins the symbol's `trade_drops` (the UNIFIED sink for every gate kill +
      margin context) into the trace
    - verdict names the killing gate + margin (e.g.
      "killed at gate 'tqs_too_low' (8x) - TQS 52 < min 60")
    - adds `gate_funnel` to the response + `trade_drops` to today_counts
  backend/scripts/probe_symbol_day.py : prints the gate funnel
  backend/tests/test_gate_funnel_v286.py : 12 unit tests

SAFETY
  - Idempotent: no-op once 'v19.34.286' present.
  - Each hunk must match its DGX anchor exactly once or the file is skipped clean.
  - Timestamped .bak per file + py_compile w/ auto-restore.
  - Pure-additive observability: NO trading-logic change.

USAGE
  python3 apply_gate_funnel_v286.py --dry-run --repo ~/Trading-and-Analysis-Platform
  python3 apply_gate_funnel_v286.py --repo ~/Trading-and-Analysis-Platform
"""
import argparse, base64, os, py_compile, shutil, sys, time
MARKER="v19.34.286"
_B64={
    "H1_OLD": "QHJvdXRlci5nZXQoIi9zeW1ib2wtdHJhY2UiKQpkZWYgZ2V0X3N5bWJvbF90cmFjZShzeW1ib2w6IHN0cik6Cg==",
    "H1_NEW": "",
    "H2_OLD": "",
    "H2_NEW": "",
    "H3_OLD": "",
    "H3_NEW": "",
    "H4_OLD": "ICAgICAgICAibGFzdF9ldmFsIjogbGFzdF9ldmFsLAogICAgICAgICJ0b2RheV9jb3VudHMiOiBjb3VudHMsCiAgICAgICAgInRpbWVzdGFtcCI6IG5vdy5pc29mb3JtYXQoKSwKICAgIH0=",
    "H4_NEW": "ICAgICAgICAibGFzdF9ldmFsIjogbGFzdF9ldmFsLAogICAgICAgICJ0b2RheV9jb3VudHMiOiBjb3VudHMsCiAgICAgICAgImdhdGVfZnVubmVsIjogZ2F0ZV9mdW5uZWwsCiAgICAgICAgInRpbWVzdGFtcCI6IG5vdy5pc29mb3JtYXQoKSwKICAgIH0=",
    "P_OLD": "",
    "P_NEW": "",
    "TEST": "",
}
def _d(k): return base64.b64decode(_B64[k]).decode("utf-8")
def log(m): print(f"[v286-applier] {m}", flush=True)

SCANNER_HUNKS=[("H1",_d("H1_OLD"),_d("H1_NEW")),("H2",_d("H2_OLD"),_d("H2_NEW")),
               ("H3",_d("H3_OLD"),_d("H3_NEW")),("H4",_d("H4_OLD"),_d("H4_NEW"))]
PROBE_HUNKS=[("P",_d("P_OLD"),_d("P_NEW"))]

def find_repo(x):
    if x: return x
    here=os.path.abspath(os.path.dirname(__file__))
    for b in (here,os.getcwd(),os.path.expanduser("~/Trading-and-Analysis-Platform")):
        c=b
        for _ in range(6):
            if os.path.isfile(os.path.join(c,"backend","routers","scanner.py")): return c
            p=os.path.dirname(c)
            if p==c: break
            c=p
    return None

def patch(path, hunks, dry):
    with open(path,encoding="utf-8") as fh: content=fh.read()
    if MARKER in content:
        log(f"already patched: {os.path.basename(path)}"); return True
    for n,o,_nw in hunks:
        cnt=content.count(o)
        if cnt!=1:
            log(f"ERROR: {os.path.basename(path)} hunk {n} matched {cnt} (expected 1). Aborting file."); return False
    for n,o,nw in hunks: content=content.replace(o,nw,1)
    if dry:
        log(f"DRY-RUN ok: {os.path.basename(path)} ({len(hunks)} hunks match)"); return True
    bak=f"{path}.bak.v286.{time.strftime('%Y%m%d-%H%M%S')}"; shutil.copy2(path,bak); log(f"backup: {bak}")
    with open(path,"w",encoding="utf-8") as fh: fh.write(content)
    try: py_compile.compile(path,doraise=True); log(f"py_compile OK: {os.path.basename(path)}")
    except py_compile.PyCompileError as e:
        log(f"ERROR py_compile {os.path.basename(path)}: {e}; restoring"); shutil.copy2(bak,path); return False
    return True

def main():
    a=argparse.ArgumentParser(); a.add_argument("--repo",default=None); a.add_argument("--dry-run",action="store_true")
    args=a.parse_args()
    repo=find_repo(args.repo)
    if not repo: log("ERROR: repo root not found. Pass --repo."); return 2
    log(f"repo: {repo}")
    scanner=os.path.join(repo,"backend","routers","scanner.py")
    probe=os.path.join(repo,"backend","scripts","probe_symbol_day.py")
    test=os.path.join(repo,"backend","tests","test_gate_funnel_v286.py")
    if not patch(scanner,SCANNER_HUNKS,args.dry_run): return 3
    if not patch(probe,PROBE_HUNKS,args.dry_run): return 4
    if args.dry_run:
        log("DRY-RUN: all hunks match + test would be written. Nothing changed."); return 0
    os.makedirs(os.path.dirname(test),exist_ok=True)
    with open(test,"w",encoding="utf-8") as fh: fh.write(_d("TEST"))
    try: py_compile.compile(test,doraise=True); log(f"wrote + compiled: {test}")
    except py_compile.PyCompileError as e: log(f"ERROR test py_compile: {e}"); return 5
    log("SUCCESS - v19.34.286 gate funnel applied.")
    log("Tests:  .venv/bin/python -m pytest backend/tests/test_gate_funnel_v286.py -q")
    log("Then ./start_backend.sh --force and re-probe: probe_symbol_day.py NVDA")
    return 0

if __name__=="__main__": sys.exit(main())
